export class PackagePeeker{lines=[];sections={};ready=!1;manifestStr;constructor(e){this.manifestStr=e}init(){this.lines=this.manifestStr.split("\n");let e=0;for(let t=0;t<this.lines.length;t++){const n=this.lines[t],i=-1!==n.indexOf('"dependencies"')?"dependencies":-1!==n.indexOf('"devDependencies"')?"devDependencies":-1!==n.indexOf('"optionalPeerDependencies"')?"optionalPeerDependencies":void 0;i&&(this.sections[i]={startLine:t,startPos:e}),e+=n.length+1}this.ready=!0}getLocation(e,t){this.ready||this.init();const n=this.lines,i=this.sections[e];if(0===n.length||!i)return;let s=i.startPos+n[i.startLine].length+1;for(let e=i.startLine+1;e<n.length;e++){const i=n[e];if(i.includes(`"${t}"`)){const n=i.indexOf(t);return{line:e+1,col:n+1,pos:s+n}}s+=i.length+1}}}